// TestLogForwarder_Handler_Enabled tests the Enabled() method
func TestLogForwarder_Handler_Enabled(t *testing.T) {
	tests := []struct {
		name      string
		minLevel  string
		testLevel slog.Level
		want      bool
	}{
		// MinLevel = DEBUG (should allow all)
		{
			name:      "DEBUG min allows DEBUG",
			minLevel:  "DEBUG",
			testLevel: slog.LevelDebug,
			want:      true,
		},
		{
			name:      "DEBUG min allows INFO",
			minLevel:  "DEBUG",
			testLevel: slog.LevelInfo,
			want:      true,
		},
		{
			name:      "DEBUG min allows WARN",
			minLevel:  "DEBUG",
			testLevel: slog.LevelWarn,
			want:      true,
		},
		{
			name:      "DEBUG min allows ERROR",
			minLevel:  "DEBUG",
			testLevel: slog.LevelError,
			want:      true,
		},

		// MinLevel = INFO (should filter DEBUG)
		{
			name:      "INFO min filters DEBUG",
			minLevel:  "INFO",
			testLevel: slog.LevelDebug,
			want:      false,
		},
		{
			name:      "INFO min allows INFO",
			minLevel:  "INFO",
			testLevel: slog.LevelInfo,
			want:      true,
		},
		{
			name:      "INFO min allows WARN",
			minLevel:  "INFO",
			testLevel: slog.LevelWarn,
			want:      true,
		},
		{
			name:      "INFO min allows ERROR",
			minLevel:  "INFO",
			testLevel: slog.LevelError,
			want:      true,
		},

		// MinLevel = WARN (should filter DEBUG and INFO)
		{
			name:      "WARN min filters DEBUG",
			minLevel:  "WARN",
			testLevel: slog.LevelDebug,
			want:      false,
		},
		{
			name:      "WARN min filters INFO",
			minLevel:  "WARN",
			testLevel: slog.LevelInfo,
			want:      false,
		},
		{
			name:      "WARN min allows WARN",
			minLevel:  "WARN",
			testLevel: slog.LevelWarn,
			want:      true,
		},
		{
			name:      "WARN min allows ERROR",
			minLevel:  "WARN",
			testLevel: slog.LevelError,
			want:      true,
		},

		// MinLevel = ERROR (should filter all except ERROR)
		{
			name:      "ERROR min filters DEBUG",
			minLevel:  "ERROR",
			testLevel: slog.LevelDebug,
			want:      false,
		},
		{
			name:      "ERROR min filters INFO",
			minLevel:  "ERROR",
			testLevel: slog.LevelInfo,
			want:      false,
		},
		{
			name:      "ERROR min filters WARN",
			minLevel:  "ERROR",
			testLevel: slog.LevelWarn,
			want:      false,
		},
		{
			name:      "ERROR min allows ERROR",
			minLevel:  "ERROR",
			testLevel: slog.LevelError,
			want:      true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Create handler with specific min level
			handler := createTestLogForwarderHandler(t, tt.minLevel, true)

			// Test Enabled()
			ctx := context.Background()
			enabled := handler.Enabled(ctx, tt.testLevel)
			assert.Equal(t, tt.want, enabled)
		})
	}
}

