// TestLogForwarder_ConcurrentPublish tests thread-safety of concurrent Handle calls
func TestLogForwarder_ConcurrentPublish(t *testing.T) {
	publishCount := 0
	var publishMu sync.Mutex

	mockNATS := &logForwarderMockNATS{
		publishFunc: func(ctx context.Context, subject string, data []byte) error {
			publishMu.Lock()
			defer publishMu.Unlock()
			publishCount++
			return nil
		},
	}

	handler := createTestLogForwarderHandlerWithNATS(t, "INFO", true, mockNATS)

	// Concurrent log publishing
	numGoroutines := 50
	var wg sync.WaitGroup
	wg.Add(numGoroutines)

	for i := 0; i < numGoroutines; i++ {
		go func(id int) {
			defer wg.Done()
			ctx := context.Background()
			record := slog.NewRecord(time.Now(), slog.LevelInfo, "concurrent message", 0)
			err := handler.Handle(ctx, record)
			assert.NoError(t, err)
		}(i)
	}

	wg.Wait()
	time.Sleep(50 * time.Millisecond)

	// Verify all publishes occurred
	publishMu.Lock()
	defer publishMu.Unlock()
	assert.Equal(t, numGoroutines, publishCount)
}

